import * as React from 'react';
import { useNavigate } from 'react-router-dom';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Drawer from '@mui/material/Drawer';
import IconButton from '@mui/material/IconButton';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import MenuIcon from '@mui/icons-material/Menu';
import Toolbar from '@mui/material/Toolbar';
import Button from '@mui/material/Button';

import { styled } from '@mui/material/styles';

import Logo from '../assets/logo.png';

const LinkButton = styled(Button)(() => ({
  // width: '90%',
  // height: '100%',
  borderRadius: '0px',
	backgroundColor: 'red',
	padding: '5px',
  "&:hover": {
    background: '#f5f5f5'
  },
  "&:active": {
    background: '#e3e3e3'
  },
  "&:focus": {
    borderBottom: '0.5px solid #333'
  },
}));

export default function Header (props) {
	const navigate = useNavigate();
	const { window } = props;
  const [ mobileOpen, setMobileOpen ] = React.useState(false);

  const handleDrawerToggle = () => {
    setMobileOpen((prevState) => !prevState);
  };

  const drawer = (
    <Box onClick={handleDrawerToggle} sx={{ textAlign: 'center' }}>
      <List>
				{/* <ListItem><Button onClick={() => navigate('/')} color='inherit'>Home</Button></ListItem> */}
				<ListItem><Button onClick={() => navigate('/collections')} color='inherit' disableRipple='true'>Collections</Button></ListItem>
				<ListItem><Button onClick={() => navigate('/about')} color='inherit' disableRipple='true'>About</Button></ListItem>
				<ListItem><Button onClick={() => navigate('/contact')} color='inherit' disableRipple='true'>Contact</Button></ListItem>
      </List>

    </Box>
  );

  const container = window !== undefined ? () => window().document.body : undefined;

	return (
		<Box sx={{ flexGrow: 1 }}>
			<AppBar position="fixed" color='inherit' sx={{ boxShadow: '0px 0.3px 15px #e3e3e3' }}>
				<Toolbar sx={{ minHeight: '56px!important' }}>

					{/* logo */}
					<Box sx={{ flexGrow: 1 }}>
						<Box
							component='img'
							src={Logo}
							sx={{ marginTop: '7px', height: '35px' }}
							alt='logo'
							onClick={() => navigate('/')}
						/>
					</Box>

					{/* Toggle menu button on mobile screen */}
 					<IconButton
 						aria-label="open drawer"
 						edge="start"
 						onClick={handleDrawerToggle}
 						sx={{ ml: 'auto', display: { sm: 'none' }, color: '#333' }}
 					>
 						<MenuIcon />
 					</IconButton>

					{/* navigation */}
					<Box sx={{ display: { xs: 'none', sm: 'block' } }}>
						{/* <Button onClick={() => navigate('/')} color='inherit'>Home</Button> */}
						<LinkButton onClick={() => navigate('/collections')} color='inherit' disableRipple='true'>Collections</LinkButton>
						<LinkButton onClick={() => navigate('/about')} color='inherit' disableRipple='true'>About</LinkButton>
						<LinkButton onClick={() => navigate('/contact')} color='inherit' disableRipple='true'>Contact</LinkButton>
					</Box>

				</Toolbar>
			</AppBar>

			<nav>
				<Drawer
					container={container}
					variant="temporary"
					open={mobileOpen}
					onClose={handleDrawerToggle}
					anchor="right"
					ModalProps={{ keepMounted: true }}
					sx={{
						display: { xs: 'block', sm: 'none' },
						'& .MuiDrawer-paper': { boxSizing: 'border-box', width: 240 },
					}}
				>
					{drawer}
				</Drawer>
			</nav>

		</Box>
	)
}
